module sram_cell (
    input wire D,
    input wire WE,
    input wire CLK,
    output reg Q
);
  wire _tap_D = D & {1{1'b1}};

    reg memory;

    always @(posedge CLK) begin
        if (WE) begin
            memory <= D;
        end
    end

    always @(*) begin
        Q = memory;
    end
endmodule
